1	type PolicyItem = { type: string; cursed?: boolean; enchantment?: number };
2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.10;
5	
6	const BLOCK_OF_THREE_PRICE = 60;
7	const CURSED_SURCHARGE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	
11	const BASE_PRICE: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	function surchargeFor(item: PolicyItem): number {
21	  const base = BASE_PRICE[item.type];
22	  let surcharge = 0;
23	  if (item.cursed) {
24	    surcharge += base * CURSED_SURCHARGE_RATE;
25	  }
26	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
27	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
28	  }
29	  return surcharge;
30	}
31	
32	function itemPremium(items: PolicyItem[]): number {
33	  const countsByType: Record<string, number> = {};
34	  for (const item of items) {
35	    countsByType[item.type] = (countsByType[item.type] || 0) + 1;
36	  }
37	
38	  let itemTotal = 0;
39	  for (const type in countsByType) {
40	    const count = countsByType[type];
41	    const isBlockOfThree = count === 3;
42	    if (isBlockOfThree) {
43	      itemTotal += BLOCK_OF_THREE_PRICE;
44	    } else {
45	      itemTotal += count * BASE_PRICE[type];
46	    }
47	  }
48	
49	  for (const item of items) {
50	    itemTotal += surchargeFor(item);
51	  }
52	
53	  return itemTotal;
54	}
55	
56	const LOYALTY_DISCOUNT_RATE = 0.2;
57	const LOYALTY_THRESHOLD_YEARS = 2;
58	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
59	
60	export function quote(
61	  policy: { customer: { years: number }; items: PolicyItem[] },
62	  options: { isFollowUp: boolean }
63	): { premium: number } {
64	  const policyBase = itemPremium(policy.items);
65	  let premium = policyBase;
66	  premium += policyBase * FIRST_INSURANCE_RATE;
67	  if (policy.customer.years >= LOYALTY_THRESHOLD_YEARS) {
68	    premium -= policyBase * LOYALTY_DISCOUNT_RATE;
69	  }
70	  if (options.isFollowUp) {
71	    premium -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
72	  }
73	  return { premium: Math.ceil(premium + PROCESSING_FEE) };
74	}
